import{_ as e,o as n,c as i,ae as s}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"React Native Expo Integration","description":"","frontmatter":{"title":"React Native Expo Integration","slug":"react-native-expo-integration"},"headers":[],"relativePath":"developer-hub/react-native-expo-integration.md","filePath":"developer-hub/react-native-expo-integration.md"}'),t={name:"developer-hub/react-native-expo-integration.md"};function o(r,a,l,p,c,d){return n(),i("div",null,[...a[0]||(a[0]=[s(`<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>This guide outlines how to integrate the <a href="https://www.npmjs.com/package/react-native-branch" target="_blank" rel="noreferrer">Branch React Native SDK</a> into an Expo-based app using the <code>@config-plugins/react-native-branch</code> <a href="https://www.npmjs.com/package/@config-plugins/react-native-branch" target="_blank" rel="noreferrer">plugin</a>.</p><div class="warning custom-block"><p class="custom-block-title">Warning</p><p>Branch supports apps built with Expo. However, the plugin is not shipped within the SDK. Please note that the plugin is <strong>community-maintained</strong>, and Branch may not be able to troubleshoot or fix plugin-dependent issues.</p></div><p>This guide covers an Expo-managed workflow. If you need full native control, see the <a href="./react-native-basic-integration.html">React Native Basic Integration</a> guide.</p><h2 id="before-you-begin" tabindex="-1">Before you begin <a class="header-anchor" href="#before-you-begin" aria-label="Permalink to &quot;Before you begin&quot;">​</a></h2><p>Before you begin this integration, make sure you:</p><ul><li><p>Have an Expo-managed or prebuild workflow using Expo SDK 54 or higher (run <code>npx expo install expo</code> to install or update)</p></li><li><p>Understand which Branch products you are implementing:</p><ul><li>Attribution and deep linking</li><li>Paid ads</li><li>Other advanced features</li></ul></li></ul><p>You will also need:</p><ul><li><p>Your Branch Key (Live or Test)</p><ul><li><a href="https://help.branch.io/account-hub/docs/profile-settings" target="_blank" rel="noreferrer">Branch Keys in legacy Branch</a></li><li><a href="https://help.branch.io/docs/credentials-new" target="_blank" rel="noreferrer">Branch Keys in new Branch</a></li></ul></li><li><p>Your Branch link domains</p></li><li><p>Confirmation whether SKAdNetwork support is required for your configuration</p></li></ul><h2 id="set-up-branch-in-your-expo-app" tabindex="-1">Set up Branch in your Expo app <a class="header-anchor" href="#set-up-branch-in-your-expo-app" aria-label="Permalink to &quot;Set up Branch in your Expo app&quot;">​</a></h2><h3 id="_1-configure-branch" tabindex="-1">1. Configure Branch <a class="header-anchor" href="#_1-configure-branch" aria-label="Permalink to &quot;1. Configure Branch&quot;">​</a></h3><p>Configure Branch for your application:</p><ul><li><a href="#">iOS Branch configuration steps</a></li><li><a href="#">Android Branch configuration steps</a></li></ul><p>Make sure to configure your default link settings as part of the setup process.</p><h3 id="_2-install-branch" tabindex="-1">2. Install Branch <a class="header-anchor" href="#_2-install-branch" aria-label="Permalink to &quot;2. Install Branch&quot;">​</a></h3><p>Install the <a href="https://www.npmjs.com/package/react-native-branch" target="_blank" rel="noreferrer">Branch React Native SDK</a> into your app.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>npx expo install react-native-branch</span></span></code></pre></div><h3 id="_3-add-plugin" tabindex="-1">3. Add plugin <a class="header-anchor" href="#_3-add-plugin" aria-label="Permalink to &quot;3. Add plugin&quot;">​</a></h3><p>Add the <a href="https://www.npmjs.com/package/@config-plugins/react-native-branch" target="_blank" rel="noreferrer">plugin</a> to your app.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>npm install @config-plugins/react-native-branch</span></span></code></pre></div><p>If you run into version issues, visit the <a href="./react-native-expo-integration.html#plugin-version-errors">Troubleshooting</a> section.</p><h3 id="_4-configure-plugin" tabindex="-1">4. Configure plugin <a class="header-anchor" href="#_4-configure-plugin" aria-label="Permalink to &quot;4. Configure plugin&quot;">​</a></h3><p>Set environment variables using <a href="https://docs.expo.dev/eas/environment-variables/" target="_blank" rel="noreferrer">EAS</a>.</p><p>If you don’t have an <code>app.config.js</code> or <code>app.config.ts</code> in your project, start by manually creating one. Then, add the following code:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>export default {</span></span>
<span class="line"><span>  plugins: [</span></span>
<span class="line"><span>    [</span></span>
<span class="line"><span>      &#39;@config-plugins/react-native-branch&#39;,</span></span>
<span class="line"><span>      {</span></span>
<span class="line"><span>        apiKey: process.env.BRANCH_API_KEY, // Required</span></span>
<span class="line"><span>        iosUniversalLinkDomains: [</span></span>
<span class="line"><span>          process.env.BRANCH_DOMAIN_LINK,</span></span>
<span class="line"><span>          process.env.BRANCH_DOMAIN_LINK_ALT,</span></span>
<span class="line"><span>        ],</span></span>
<span class="line"><span>      },</span></span>
<span class="line"><span>    ],</span></span>
<span class="line"><span>  ],</span></span>
<span class="line"><span>  ios: {</span></span>
<span class="line"><span>    associatedDomains: [</span></span>
<span class="line"><span>      \`applinks:\${process.env.BRANCH_DOMAIN_LINK}\`,</span></span>
<span class="line"><span>      \`applinks:\${process.env.BRANCH_DOMAIN_LINK_ALT}\`,</span></span>
<span class="line"><span>    ],</span></span>
<span class="line"><span>  },</span></span>
<span class="line"><span>  android: {</span></span>
<span class="line"><span>    intentFilters: [</span></span>
<span class="line"><span>      {</span></span>
<span class="line"><span>        action: &quot;VIEW&quot;,</span></span>
<span class="line"><span>        autoVerify: true,</span></span>
<span class="line"><span>        category: [&quot;BROWSABLE&quot;, &quot;DEFAULT&quot;],</span></span>
<span class="line"><span>        data: [</span></span>
<span class="line"><span>          { scheme: &#39;https&#39;, host: \`\${process.env.BRANCH_DOMAIN_LINK}\` },</span></span>
<span class="line"><span>          { scheme: &#39;https&#39;, host: \`\${process.env.BRANCH_DOMAIN_LINK_ALT}\` },</span></span>
<span class="line"><span>        ],</span></span>
<span class="line"><span>      },</span></span>
<span class="line"><span>    ],</span></span>
<span class="line"><span>  },</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>If your build is failing in local development after configuring the plugin, see the <a href="./react-native-expo-integration.html#build-fails-without-branchapikey-in-local-development">Troubleshooting</a> section.</p><h4 id="iosuniversallinkdomains" tabindex="-1">iosUniversalLinkDomains <a class="header-anchor" href="#iosuniversallinkdomains" aria-label="Permalink to &quot;iosUniversalLinkDomains&quot;">​</a></h4><p>The <code>iosUniversalLinkDomains</code> option registers your Branch domains as iOS associated domains for Universal Links. Include both your primary and alternate (<code>-alternate</code>) link domains if your app uses both.</p><p>This is separate from <code>ios.associatedDomains</code>, which establishes a secure association between your domains and your app.</p><p>Universal Links requires both <code>iosUniversalLinkDomains</code> and <code>ios.associatedDomains</code> to work.</p><h3 id="_5-subscribe-to-deep-link-data" tabindex="-1">5. Subscribe to deep link data <a class="header-anchor" href="#_5-subscribe-to-deep-link-data" aria-label="Permalink to &quot;5. Subscribe to deep link data&quot;">​</a></h3><p>The plugin handles native Branch initialization automatically. For details on native Branch initialization, see the <a href="./react-native-basic-integration.html">React Native Basic Integration</a> guide.</p><p>To listen for deep link data, subscribe in your app&#39;s entry point:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>import branch from &#39;react-native-branch&#39;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>branch.subscribe(({ error, params }) =&gt; {</span></span>
<span class="line"><span>  if (error) {</span></span>
<span class="line"><span>    console.error(&#39;Branch error:&#39;, error)</span></span>
<span class="line"><span>    return</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  console.log(&#39;Branch params:&#39;, params)</span></span>
<span class="line"><span>})</span></span></code></pre></div><h3 id="_6-optional-set-up-paid-ads" tabindex="-1">6. (Optional) Set up paid ads <a class="header-anchor" href="#_6-optional-set-up-paid-ads" aria-label="Permalink to &quot;6. (Optional) Set up paid ads&quot;">​</a></h3><p>If you&#39;re using Branch for paid ad attribution, additional setup is required.</p><p>See the following guides to set up and test your paid ads implementation:</p><ul><li><a href="./enable-skadnetwork.html">Enable SKAdNetwork</a></li><li><a href="./testing-ads-campaign-setup.html">Test Ads Campaign Setup</a></li></ul><h3 id="_7-validate-integration" tabindex="-1">7. Validate integration <a class="header-anchor" href="#_7-validate-integration" aria-label="Permalink to &quot;7. Validate integration&quot;">​</a></h3><p>Before testing on device, use the <a href="./link-validator.html">Link Validator</a> in Branch to confirm your links are configured correctly and preview the expected user flow across different platforms and click sources.</p><p>Then validate your integration using the three scenarios below. In each case, your <code>subscribe</code> callback should receive and log the link data.</p><ol><li><strong>Test Universal Link opening:</strong> Open a Branch Link from Safari (iOS) and Chrome (Android). The app should open directly without extra dialogs or browser redirects.</li><li><strong>Test cold-start deep link behavior:</strong> Force quit the app, then open a Branch Link. The app should launch and take you to your content.</li><li><strong>Test background resume behavior:</strong> With the app backgrounded, tap a Branch Link. The app should resume and take you to your content.</li></ol><p>For additional validation and testing, use the following guides:</p><p><strong>iOS</strong></p><ul><li><a href="./ios-basic-integration.html#8-validate-integration">iOS Validation</a></li><li><a href="./ios-testing.html">iOS Testing</a></li></ul><p><strong>Android</strong></p><ul><li><a href="./android-basic-integration.html#8-validate-integration">Android Validation</a></li><li><a href="./android-testing.html">Android Testing</a></li></ul><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><p>Once you’ve integrated Branch into your Expo app, you can use any of the features documented in the <a href="https://help.branch.io/developer-hub/docs/react-native-full-reference" target="_blank" rel="noreferrer">React Native Full Reference</a> guide, including creating Branch Links, tracking Branch Events, and handling Branch Universal Objects.</p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><p>For general iOS and Android troubleshooting suggestions, use the following guides:</p><ul><li><a href="./ios-troubleshooting.html">iOS Troubleshooting</a></li><li><a href="./android-troubleshooting.html">Android Troubleshooting</a></li></ul><h4 id="plugin-version-errors" tabindex="-1">Plugin version errors <a class="header-anchor" href="#plugin-version-errors" aria-label="Permalink to &quot;Plugin version errors&quot;">​</a></h4><p>If running <code>npm install @config-plugins/react-native-branch</code> results in version errors, try the following command instead:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>npm install @config-plugins/react-native-branch --legacy-peer-deps</span></span></code></pre></div><h4 id="build-fails-without-branch-api-key-in-local-development" tabindex="-1">Build fails without BRANCH_API_KEY in local development <a class="header-anchor" href="#build-fails-without-branch-api-key-in-local-development" aria-label="Permalink to &quot;Build fails without BRANCH\\_API\\_KEY in local development&quot;">​</a></h4><p>If <code>BRANCH_API_KEY</code> is not set in your environment, the plugin will fail the build, even if you&#39;re not testing Branch functionality. To avoid this, conditionally load the plugin only for production builds:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>export default {</span></span>
<span class="line"><span>  plugins: IS_DEV</span></span>
<span class="line"><span>    ? [...plugins, ...devPlugins]</span></span>
<span class="line"><span>    : [...plugins, ...prodPlugins],</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>Place the <code>@config-plugins/react-native-branch</code> plugin inside <code>prodPlugins</code>.</p><h4 id="prebuild-fails" tabindex="-1">Prebuild fails <a class="header-anchor" href="#prebuild-fails" aria-label="Permalink to &quot;Prebuild fails&quot;">​</a></h4><p>If prebuild fails after adding the <code>@config-plugins/react-native-branch</code> plugin, try running a clean prebuild:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>npx expo prebuild --clean</span></span></code></pre></div><h4 id="unable-to-use-both-test-and-live-branch-keys" tabindex="-1">Unable to use both Test and Live Branch Keys <a class="header-anchor" href="#unable-to-use-both-test-and-live-branch-keys" aria-label="Permalink to &quot;Unable to use both Test and Live Branch Keys&quot;">​</a></h4><p>The plugin only accepts one API key.</p><p>Workaround options:</p><ul><li>Use separate builds for Test and Live</li><li>Use only your Branch Live Key across all your environments</li><li>Implement custom built-time logic</li></ul><h4 id="deep-links-do-not-open-in-the-app" tabindex="-1">Deep links do not open in the app <a class="header-anchor" href="#deep-links-do-not-open-in-the-app" aria-label="Permalink to &quot;Deep links do not open in the app&quot;">​</a></h4><p>If your deep links are not properly opening your app:</p><ul><li>Verify <a href="./react-native-expo-integration.html#4-configure-plugin">associatedDomains (iOS)</a></li><li>Verify <a href="./react-native-expo-integration.html#4-configure-plugin">intentFilters (Android)</a></li><li>Confirm <a href="./basic-link-configuration.html#5-link-domain">domain configuration</a> in Branch</li><li>Confirm <a href="./ios-testing.html">AASA file</a> is accessible</li></ul><h4 id="skadnetwork-attribution-is-unclear" tabindex="-1">SKAdNetwork attribution is unclear <a class="header-anchor" href="#skadnetwork-attribution-is-unclear" aria-label="Permalink to &quot;SKAdNetwork attribution is unclear&quot;">​</a></h4><p>If your SKAdNetwork attribution data is not showing up or doesn’t look correct in Branch:</p><ul><li><p>Confirm SKAdNetwork IDs are registered</p></li><li><p>Validate Branch reporting</p></li><li><p>Test install flow from paid campaign</p></li></ul><p>For SKAdNetwork setup and validation, see our <a href="./enable-skadnetwork.html">Enable SKAdNetwork</a> guide.</p><h4 id="branch-analytics-fields-are-empty-after-removing-firebase" tabindex="-1">Branch analytics fields are empty after removing Firebase <a class="header-anchor" href="#branch-analytics-fields-are-empty-after-removing-firebase" aria-label="Permalink to &quot;Branch analytics fields are empty after removing Firebase&quot;">​</a></h4><p>If you migrated away from the Firebase SDK and Branch analytics fields like <code>$~campaign</code> are unpopulated, you may need to explicitly install <code>expo-tracking-transparency</code>. On Android, this library was previously bundled with Firebase in Expo environments.</p><p><code>npx expo install expo-tracking-transparency</code></p><p>Also confirm that your Proguard <code>-keep</code> rules are correctly configured for the Branch React Native SDK.</p>`,77)])])}const g=e(t,[["render",o]]);export{u as __pageData,g as default};
